import { useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../services/api";

function AddMatch() {
  const [formData, setFormData] = useState({
    teamA: "",
    teamB: "",
    scoreA: "0/0",
    scoreB: "0/0",
    overs: "0.0",
    status: "Upcoming",
  });
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await API.post("/matches", formData);
      alert("Match added successfully!");
      navigate("/matches");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to add match");
    }
  };

  return (
    <div className="auth-card" style={{ maxWidth: '500px' }}>
      <h2>Add New Match</h2>
      {error && <p className="error-msg">{error}</p>}
      <form onSubmit={handleSubmit}>
        <div className="input-group">
          <label>Team A</label>
          <input type="text" name="teamA" value={formData.teamA} onChange={handleChange} required />
        </div>
        <div className="input-group">
          <label>Team B</label>
          <input type="text" name="teamB" value={formData.teamB} onChange={handleChange} required />
        </div>
        <div className="input-group">
          <label>Score A (e.g., 150/3)</label>
          <input type="text" name="scoreA" value={formData.scoreA} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Score B (e.g., 140/5)</label>
          <input type="text" name="scoreB" value={formData.scoreB} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Overs (e.g., 18.2)</label>
          <input type="text" name="overs" value={formData.overs} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Status</label>
          <select name="status" value={formData.status} onChange={handleChange} className="input-select" style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #ddd' }}>
            <option value="Upcoming">Upcoming</option>
            <option value="Live">Live</option>
            <option value="Completed">Completed</option>
          </select>
        </div>
        <button type="submit" className="auth-btn">Save Match</button>
      </form>
    </div>
  );
}

export default AddMatch;
